    "CVE-DEMO-2026-002": {
      "affected_versions": "QuartzDB Server 4.0.0 through 4.3.2 when the optional /v1/query/raw REST endpoint is enabled",
      "recommended_fix": "Upgrade to QuartzDB Server 4.3.3 or later",
      "interim_mitigation_if_cannot_upgrade": "Disable the /v1/query/raw endpoint via rest.raw_query.enabled = false"
    },
    "CVE-DEMO-2026-012": {
      "affected_versions": "QuartzDB Server 4.1.0 through 4.3.4 (3.x branch not affected)",
      "recommended_fix": "Upgrade to QuartzDB Server 4.3.5 or later",
      "interim_mitigation_if_cannot_upgrade": "Set quartzdb.logger.format_lookups = false and restart; if you cannot restart/upgrade, remove the affected library from the classpath"
    }
  },
  "combined_patch_plan": {
    "minimum_target_version_to_satisfy_both": "QuartzDB Server 4.3.5 or later",
    "recommended_sequencing": [
      {
        "mode": "preferred",
        "steps": [
          "Upgrade QuartzDB Server to 4.3.5+ as the primary remediation (this satisfies both CVE-DEMO-2026-002 and CVE-DEMO-2026-012 fixed-version requirements)."
        ],
        "downtime_or_restart_expectations": "Evidence does not specify upgrade downtime; follow your standard upgrade procedure. Interim logger mitigation explicitly calls for a restart (upgrade may require a restart/redeployment per your operational runbook)."
      },
      {
        "mode": "if_full_upgrade_cannot_happen_immediately",
        "steps": [
          "1) For CVE-DEMO-2026-002: disable the /v1/query/raw endpoint (rest.raw_query.enabled = false).",
          "2) For CVE-DEMO-2026-012: apply quartzdb.logger.format_lookups = false and restart (or remove the affected library from the classpath if restart/upgrade is not possible)."
        ],
        "overlap": "No overlapping fixes are indicated; the endpoint mitigation and logger mitigation address different mechanisms."
      }
    ]
  }
}
